class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[n] = 1

        for i in range(n - 1, -1, -1):
            if s[i] == '0':
                dp[i] = 0
                continue
            num = 0
            ways = 0
            for j in range(i, n):
                num = num * 10 + int(s[j])
                if num > k:
                    break
                ways = (ways + dp[j + 1]) % MOD
            dp[i] = ways

        return dp[0]

